+				"result": map[string]any{
+					"ok": true,
+				},
+			},
+		})
+	}))
+	defer srv.Close()
+
+	svc, err := scriptapi.NewService(context.Background(),
+		option.WithoutAuthentication(),
+		option.WithHTTPClient(srv.Client()),
+		option.WithEndpoint(srv.URL+"/"),
