+		t.Fatalf("unmarshal: %v", err)
+	}
+	op, ok := parsed["operation"].(map[string]any)
+	if !ok {
+		t.Fatalf("missing operation: %#v", parsed)
+	}
+	if done, _ := op["done"].(bool); !done {
+		t.Fatalf("expected done=true: %#v", op)
+	}
+}
